### Version

Yosys 0.23+45 (git sha1 a64ed824e, clang 10.0.0-4ubuntu1 -fPIC -Os)

### On which OS did this happen?

Linux

### Reproduction Steps

Hi , 

Getting equivalnce issues when checking in between RTL and netlist. The netlist is generated using mapping and inferencing full adders : 

Input RTL : rippler_adder.v


module ripplemod(a, b, cin, sum, cout);

input [7:0] a;

input [7:0] b;

input cin;

output [7:0]sum;

output cout;

wire[6:0] c;

fulladd a1(a[0],b[0],cin,sum[0],c[0]);

fulladd a2(a[1],b[1],c[0],sum[1],c[1]);

fulladd a3(a[2],b[2],c[1],sum[2],c[2]);

fulladd a4(a[3],b[3],c[2],sum[3],c[3]);

fulladd a5(a[4],b[4],c[3],sum[4],c[4]);

fulladd a6(a[5],b[5],c[4],sum[5],c[5]);

fulladd a7(a[6],b[6],c[5],sum[6],c[6]);

fulladd a8(a[7],b[7],c[6],sum[7],cout);

endmodule

 

module fulladd(a, b, cin, sum, cout);

input a;

input b;


input cin;

output sum;

output cout;

assign sum= (a&!b&!cin) | (!a&b&!cin) | (!a&!b&cin) | (a&b&cin);

//(A&!B&!CI) | (!A&B&!CI) | (!A&!B&CI) | (A&B&CI)

assign cout=((a&b)|(b&cin)|(a&cin));

endmodule


----------------------------------------------
Yosys Script : 

# read design
read -sv  rippler_adder.v
hierarchy -top ripplemod
proc; fsm; opt; memory; opt

synth -flatten; 


        extract_fa -fa -v
        extract_fa -ha -v
       
techmap -map /pdks/sky130A/libs.tech/openlane/sky130_fd_sc_hd/fa_map.v

dfflibmap -liberty ./sky130_fd_sc_hd__tt_025C_1v80.lib 

# mapping logic to mycells.lib
abc -liberty  ./sky130_fd_sc_hd__tt_025C_1v80.lib

opt_clean -purge

write_verilog RA_synth_FV.v





